import React, { useEffect, useMemo, useRef, useState } from 'react';
import SoftwareTypeForm from './SoftwareTypeForm';
import { getSoftwareTypes, createSoftwareType, updateSoftwareType, deleteSoftwareType, SoftwareType } from '../services/api';

const filterOptions = ['Active Software Types', 'All Software Types'];
const columnFilterOptions = [
  'Contains',
  'Does not contain',
  'Equals',
  'Does not equal',
  'Begins with',
  'Ends with',
  'Blank',
  'Not blank',
] as const;

type ColumnField = 'display_name' | 'description' | 'enable_compliance';
type ColumnFilterOperator = (typeof columnFilterOptions)[number];
type ColumnFilter = {
  operator: ColumnFilterOperator;
  value: string;
};

const allColumns = [
  { field: 'display_name' as ColumnField, label: 'Software Type' },
  { field: 'description' as ColumnField, label: 'Description' },
  { field: 'enable_compliance' as ColumnField, label: 'Enable Compliance' },
];

const defaultColumnFilter: ColumnFilter = {
  operator: 'Contains',
  value: '',
};

const getSoftwareTypeColumnValue = (item: SoftwareType, field: ColumnField) => {
  if (field === 'enable_compliance') {
    return item.enable_compliance ? 'Yes' : 'No';
  }

  return item[field] ?? '';
};

const doesValueMatchColumnFilter = (rawValue: string, filter: ColumnFilter) => {
  const value = rawValue.trim().toLowerCase();
  const filterValue = filter.value.trim().toLowerCase();

  if (filter.operator === 'Blank') {
    return value.length === 0;
  }

  if (filter.operator === 'Not blank') {
    return value.length > 0;
  }

  if (!filterValue) {
    return true;
  }

  switch (filter.operator) {
    case 'Contains':
      return value.includes(filterValue);
    case 'Does not contain':
      return !value.includes(filterValue);
    case 'Equals':
      return value === filterValue;
    case 'Does not equal':
      return value !== filterValue;
    case 'Begins with':
      return value.startsWith(filterValue);
    case 'Ends with':
      return value.endsWith(filterValue);
    default:
      return true;
  }
};

const SoftwareTypeTable: React.FC = () => {
  const [softwareTypes, setSoftwareTypes] = useState<SoftwareType[]>([]);
  const [open, setOpen] = useState<boolean>(false);
  const [editing, setEditing] = useState<SoftwareType | null>(null);
  const [activeFilter, setActiveFilter] = useState<string>(filterOptions[0]);
  const [actionAnchorEl, setActionAnchorEl] = useState<HTMLElement | null>(null);
  const [actionRow, setActionRow] = useState<SoftwareType | null>(null);
  const [columnsAnchorEl, setColumnsAnchorEl] = useState<HTMLElement | null>(null);
  const [visibleColumns, setVisibleColumns] = useState<string[]>(allColumns.map((column) => column.field));
  const [filterMenuField, setFilterMenuField] = useState<ColumnField | null>(null);
  const [columnFilters, setColumnFilters] = useState<Partial<Record<ColumnField, ColumnFilter>>>({});
  const [draftColumnFilter, setDraftColumnFilter] = useState<ColumnFilter>(defaultColumnFilter);
  const [currentPage, setCurrentPage] = useState<number>(1);
  const [pageSize, setPageSize] = useState<number>(10);
  const [loading, setLoading] = useState<boolean>(false);
  const [saving, setSaving] = useState<boolean>(false);
  const actionMenuRef = useRef<HTMLDivElement>(null);
  const columnsMenuRef = useRef<HTMLDivElement>(null);
  const filterMenuRef = useRef<HTMLDivElement>(null);

  const fetchSoftwareTypes = async () => {
    setLoading(true);
    try {
      const response = await getSoftwareTypes();
      setSoftwareTypes(response.data);
    } catch (error) {
      console.error('Error fetching software types:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchSoftwareTypes();
  }, []);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (
        actionMenuRef.current &&
        !actionMenuRef.current.contains(event.target as Node) &&
        actionAnchorEl &&
        !actionAnchorEl.contains(event.target as Node)
      ) {
        setActionAnchorEl(null);
      }
      if (columnsMenuRef.current && !columnsMenuRef.current.contains(event.target as Node)) {
        setColumnsAnchorEl(null);
      }
      if (filterMenuRef.current && !filterMenuRef.current.contains(event.target as Node)) {
        setFilterMenuField(null);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [actionAnchorEl]);

  const filteredSoftwareTypes = useMemo(() => {
    return softwareTypes.filter((item) => {
      const matchesActiveFilter = activeFilter === filterOptions[0] ? item.enable_compliance : true;

      if (!matchesActiveFilter) {
        return false;
      }

      return allColumns.every((column) => {
        const filter = columnFilters[column.field];
        if (!filter) {
          return true;
        }

        return doesValueMatchColumnFilter(getSoftwareTypeColumnValue(item, column.field), filter);
      });
    });
  }, [activeFilter, columnFilters, softwareTypes]);

  useEffect(() => {
    if (currentPage > totalPages) {
      setCurrentPage(totalPages);
    }
  }, [currentPage, totalPages]);

  const totalPages = Math.max(1, Math.ceil(filteredSoftwareTypes.length / pageSize));
  const startIndex = (currentPage - 1) * pageSize;
  const endIndex = startIndex + pageSize;
  const paginatedData = filteredSoftwareTypes.slice(startIndex, endIndex);

  const handleOpen = (item: SoftwareType | null = null) => {
    setEditing(item);
    setOpen(true);
  };

  const handleClose = () => {
    setOpen(false);
    setEditing(null);
  };

  const handleSave = async () => {
    setSaving(true);
    try {
      await fetchSoftwareTypes();
      handleClose();
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (window.confirm('Are you sure you want to delete this software type?')) {
      try {
        await deleteSoftwareType(id);
        fetchSoftwareTypes();
        setActionAnchorEl(null);
      } catch (error) {
        console.error('Error deleting software type:', error);
      }
    }
  };

  const handleClearFilters = () => {
    setActiveFilter(filterOptions[0]);
    setColumnFilters({});
    setFilterMenuField(null);
    setDraftColumnFilter(defaultColumnFilter);
    setCurrentPage(1);
  };

  const handleOpenColumnFilter = (field: ColumnField) => {
    setDraftColumnFilter(columnFilters[field] ?? defaultColumnFilter);
    setFilterMenuField((currentField) => (currentField === field ? null : field));
  };

  const handleApplyColumnFilter = (field: ColumnField) => {
    setColumnFilters((prev) => ({
      ...prev,
      [field]: draftColumnFilter,
    }));
    setFilterMenuField(null);
    setCurrentPage(1);
  };

  const handleResetColumnFilter = (field: ColumnField) => {
    setColumnFilters((prev) => {
      const next = { ...prev };
      delete next[field];
      return next;
    });
    setDraftColumnFilter(defaultColumnFilter);
    setFilterMenuField(null);
    setCurrentPage(1);
  };

  const handlePageChange = (page: number) => {
    if (page >= 1 && page <= totalPages) {
      setCurrentPage(page);
    }
  };

  const handlePageSizeChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setPageSize(parseInt(e.target.value, 10));
    setCurrentPage(1);
  };

  const actionMenuStyle = actionAnchorEl
    ? {
        position: 'absolute' as const,
        top: actionAnchorEl.getBoundingClientRect().bottom + window.scrollY + 8,
        left: actionAnchorEl.getBoundingClientRect().left + window.scrollX,
      }
    : undefined;

  const renderColumnHeader = (field: ColumnField, label: string) => {
    const hasFilter = Boolean(columnFilters[field]);
    const isValueDisabled = draftColumnFilter.operator === 'Blank' || draftColumnFilter.operator === 'Not blank';

    return (
      <th className="relative px-4 py-4 text-left text-xs font-semibold uppercase tracking-wider text-slate-500">
        <div className="flex items-center justify-between gap-2">
          <span>{label}</span>
          <button
            type="button"
            onClick={(event) => {
              event.stopPropagation();
              handleOpenColumnFilter(field);
            }}
            className={`rounded p-1 hover:bg-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500 ${
              hasFilter ? 'text-blue-600' : 'text-slate-500'
            }`}
            aria-label={`Filter ${label}`}
          >
            <svg className="h-3.5 w-3.5" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg">
              <path d="M2 3H14M4.5 7H11.5M6.5 11H9.5" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" />
            </svg>
          </button>
        </div>

        {filterMenuField === field && (
          <div
            ref={filterMenuRef}
            className="absolute right-2 top-11 z-20 w-48 rounded-md border border-slate-300 bg-white p-3 text-slate-700 shadow-xl"
          >
            <select
              value={draftColumnFilter.operator}
              onChange={(event) =>
                setDraftColumnFilter((prev) => ({
                  ...prev,
                  operator: event.target.value as ColumnFilterOperator,
                }))
              }
              className="mb-2 w-full rounded border border-slate-300 bg-white px-2 py-2 text-sm font-normal normal-case tracking-normal text-slate-900 focus:border-blue-500 focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              {columnFilterOptions.map((option) => (
                <option key={option} value={option}>
                  {option}
                </option>
              ))}
            </select>
            <div className="relative">
              <span className="pointer-events-none absolute left-2 top-1/2 -translate-y-1/2 text-slate-400">
                <svg className="h-3.5 w-3.5" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg">
                  <path
                    d="M7 12A5 5 0 1 0 7 2a5 5 0 0 0 0 10ZM10.5 10.5L14 14"
                    stroke="currentColor"
                    strokeWidth="1.5"
                    strokeLinecap="round"
                  />
                </svg>
              </span>
              <input
                value={draftColumnFilter.value}
                onChange={(event) => setDraftColumnFilter((prev) => ({ ...prev, value: event.target.value }))}
                disabled={isValueDisabled}
                placeholder="Filter..."
                className="w-full rounded border border-slate-300 bg-white py-2 pl-7 pr-2 text-sm font-normal normal-case tracking-normal text-slate-900 placeholder:text-slate-400 focus:border-blue-500 focus:outline-none focus:ring-2 focus:ring-blue-500 disabled:bg-slate-100"
              />
            </div>
            <div className="mt-4 flex justify-end gap-2">
              <button
                type="button"
                onClick={() => handleApplyColumnFilter(field)}
                className="rounded border border-slate-300 bg-white px-3 py-2 text-sm font-normal normal-case tracking-normal text-slate-700 hover:bg-slate-50 focus:outline-none focus:ring-2 focus:ring-blue-500"
              >
                Apply
              </button>
              <button
                type="button"
                onClick={() => handleResetColumnFilter(field)}
                className="rounded border border-slate-300 bg-white px-3 py-2 text-sm font-normal normal-case tracking-normal text-slate-700 hover:bg-slate-50 focus:outline-none focus:ring-2 focus:ring-blue-500"
              >
                Reset
              </button>
            </div>
          </div>
        )}
      </th>
    );
  };

  return (
    <div className="bg-white rounded-lg shadow-sm p-6 space-y-5">
      <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-4 mb-4">
        <div className="flex flex-col md:flex-row md:items-center gap-3">
          <select
            value={activeFilter}
            onChange={(e) => setActiveFilter(e.target.value)}
            className="w-full md:w-64 rounded-md border border-slate-300 bg-white px-3 py-2 text-sm text-slate-900 focus:border-blue-500 focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            {filterOptions.map((option) => (
              <option key={option} value={option}>
                {option}
              </option>
            ))}
          </select>

          <button
            onClick={() => handleOpen()}
            className="rounded-md bg-blue-600 px-4 py-2 text-sm font-medium text-white hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500"
            type="button"
          >
            New Software Type
          </button>
        </div>

        <div className="flex flex-wrap items-center gap-2">
          <button
            onClick={handleClearFilters}
            className="rounded-md border border-slate-300 bg-white px-4 py-2 text-sm text-slate-700 hover:bg-slate-50 focus:outline-none focus:ring-2 focus:ring-blue-500"
            type="button"
          >
            Clear All Filters
          </button>
          <div className="relative">
            <button
              onClick={(e) => setColumnsAnchorEl(e.currentTarget)}
              className="rounded-md border border-slate-300 bg-white px-4 py-2 text-sm text-slate-700 hover:bg-slate-50 focus:outline-none focus:ring-2 focus:ring-blue-500"
              type="button"
            >
              ▶ Select Columns
            </button>
            {columnsAnchorEl && (
              <div
                ref={columnsMenuRef}
                className="absolute right-0 z-10 mt-1 w-56 rounded-md border border-slate-300 bg-white p-2 shadow-lg"
              >
                {allColumns.map((column) => (
                  <label key={column.field} className="flex cursor-pointer items-center gap-2 rounded-sm px-2 py-1 hover:bg-slate-50">
                    <input
                      type="checkbox"
                      checked={visibleColumns.includes(column.field)}
                      onChange={() => {
                        setVisibleColumns((prev) =>
                          prev.includes(column.field)
                            ? prev.filter((value) => value !== column.field)
                            : [...prev, column.field]
                        );
                      }}
                      className="h-4 w-4 rounded border-slate-300 text-blue-600 focus:ring-blue-500"
                    />
                    <span className="text-sm text-slate-700">{column.label}</span>
                  </label>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>

      {loading && (
        <div className="flex justify-center items-center py-12">
          <span className="animate-spin rounded-full h-10 w-10 border-t-2 border-b-2 border-blue-600"></span>
        </div>
      )}

      <div className="overflow-x-auto rounded-lg border border-slate-200 bg-white shadow-sm">
        <table className="w-full min-w-[700px] divide-y divide-slate-200">
          <thead className="bg-[#fafafa]">
            <tr>
              <th className="w-12 px-4 py-4 text-left text-xs font-semibold uppercase tracking-wider text-slate-500"></th>
              {visibleColumns.includes('display_name') && (
                renderColumnHeader('display_name', 'Software Type')
              )}
              {visibleColumns.includes('description') && (
                renderColumnHeader('description', 'Description')
              )}
              {visibleColumns.includes('enable_compliance') && (
                renderColumnHeader('enable_compliance', 'Enable Compliance')
              )}
            </tr>
          </thead>
          <tbody className="bg-white divide-y divide-slate-200">
            {paginatedData.map((item) => (
              <tr key={item.id} className="hover:bg-slate-50 transition-colors duration-150">
                <td className="w-12 px-4 py-4 whitespace-nowrap text-sm text-slate-900">
                  <button
                    onClick={(event) => {
                      event.stopPropagation();
                      setActionRow(item);
                      setActionAnchorEl(event.currentTarget);
                    }}
                    className="text-slate-400 hover:text-slate-600"
                    aria-label="Actions"
                    type="button"
                  >
                    <svg width="16" height="16" viewBox="0 0 20 20" fill="none" xmlns="http://www.w3.org/2000/svg">
                      <rect y="4" width="20" height="2" rx="1" fill="currentColor" />
                      <rect y="9" width="20" height="2" rx="1" fill="currentColor" />
                      <rect y="14" width="20" height="2" rx="1" fill="currentColor" />
                    </svg>
                  </button>
                </td>
                {visibleColumns.includes('display_name') && <td className="px-4 py-4 whitespace-nowrap text-sm text-slate-900">{item.display_name}</td>}
                {visibleColumns.includes('description') && <td className="px-4 py-4 whitespace-nowrap text-sm text-slate-900">{item.description}</td>}
                {visibleColumns.includes('enable_compliance') && (
                  <td className="px-4 py-4 whitespace-nowrap text-sm text-slate-900">{getSoftwareTypeColumnValue(item, 'enable_compliance')}</td>
                )}
              </tr>
            ))}
            {paginatedData.length === 0 && (
              <tr>
                <td colSpan={visibleColumns.length + 1} className="px-6 py-8 text-center text-sm text-slate-500">
                  No software types found
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {actionAnchorEl && (
        <div
          ref={actionMenuRef}
          className="fixed z-10 w-40 rounded-md border border-slate-200 bg-white shadow-lg"
          data-action-menu
          style={actionMenuStyle}
        >
          <button
            onClick={() => {
              if (actionRow) handleOpen(actionRow);
              setActionAnchorEl(null);
            }}
            className="block w-full px-4 py-2 text-left text-sm text-slate-700 hover:bg-slate-100"
            type="button"
          >
            Edit
          </button>
          <button
            onClick={() => {
              if (actionRow) handleDelete(actionRow.id);
              setActionAnchorEl(null);
            }}
            className="block w-full px-4 py-2 text-left text-sm text-slate-700 hover:bg-slate-100"
            type="button"
          >
            Delete
          </button>
        </div>
      )}

      <div className="mt-6 flex flex-col gap-4 md:flex-row md:items-center md:justify-between">
        <div className="flex items-center gap-2 text-sm text-slate-700">
          <span>Page Size:</span>
          <select
            value={pageSize}
            onChange={handlePageSizeChange}
            className="rounded-md border border-slate-300 bg-white px-3 py-1 text-sm focus:border-blue-500 focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            <option value={10}>10</option>
            <option value={25}>25</option>
            <option value={50}>50</option>
          </select>
        </div>

        <div className="flex flex-wrap items-center gap-3 text-sm text-slate-600">
          <span>
            {filteredSoftwareTypes.length === 0 ? '0 to 0 of 0' : `${startIndex + 1} to ${Math.min(endIndex, filteredSoftwareTypes.length)} of ${filteredSoftwareTypes.length}`}
          </span>
          <div className="flex items-center gap-2">
            <button
              onClick={() => handlePageChange(currentPage - 1)}
              disabled={currentPage === 1}
              className="rounded-md border border-slate-300 px-3 py-1 text-sm text-slate-700 hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed"
              type="button"
            >
              ←
            </button>
            <span className="text-sm text-slate-600">Page {currentPage} of {totalPages === 0 ? 1 : totalPages}</span>
            <button
              onClick={() => handlePageChange(currentPage + 1)}
              disabled={currentPage === totalPages}
              className="rounded-md border border-slate-300 px-3 py-1 text-sm text-slate-700 hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed"
              type="button"
            >
              →
            </button>
          </div>
        </div>
      </div>

      {open && (
        <div className="fixed inset-0 z-50 overflow-y-auto">
          <div className="fixed inset-0 bg-slate-900/50" aria-hidden="true" onClick={handleClose}></div>
          <div className="relative mx-auto mt-20 w-full max-w-3xl rounded-3xl bg-white p-6 shadow-2xl">
            <div className="mb-6 flex items-center justify-between">
              <div>
                <h2 className="text-xl font-semibold text-slate-900">
                  {editing ? 'Edit Software Type' : 'Add Software Type'}
                </h2>
                <p className="text-sm text-slate-500">
                  {editing ? 'Update software type details.' : 'Create a new software type.'}
                </p>
              </div>
              <button
                type="button"
                onClick={handleClose}
                className="rounded-full bg-slate-100 p-2 text-slate-500 hover:bg-slate-200"
              >
                ×
              </button>
            </div>
            <SoftwareTypeForm editing={editing} onSave={handleSave} onClose={handleClose} saving={saving} />
          </div>
        </div>
      )}
    </div>
  );
};

export default SoftwareTypeTable;
